//! Immutable frame description — the UI DSL.
//! The event loop builds snapshots; the render actor draws them.
//! Zero blocking I/O in the event loop by design.

use crate::model::VisibleRegion;
use crate::ui::elements::Element;

#[derive(Clone)]
pub struct Snapshot {
    pub elements: Vec<Element>,
    pub line_counts: Vec<usize>,
    pub total_lines: usize,
    pub input: String,
    pub cursor_pos: usize,
    pub hint_text: String,
    pub at_suggestions: Option<Vec<String>>,
    pub at_selected: Option<usize>,
    pub turn_active: bool,
    pub spinner_frame: char,
    pub scroll: usize,
    /// Elapsed seconds since turn started. Captured at snapshot creation time.
    pub turn_elapsed_secs: Option<f64>,
    pub provider: String,
    pub model: String,
    /// Flash countdown for invalid input feedback.
    pub input_flash: u8,
    /// Placeholder text shown when input is empty.
    pub placeholder: String,
}

impl Snapshot {
    pub fn element_count(&self) -> usize {
        self.elements.len()
    }

    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        let start = skip.min(self.elements.len());
        let end = (start + take).min(self.elements.len());
        &self.elements[start..end]
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements[start_idx..end_idx.min(self.elements.len())],
            skip_lines,
        }
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }
}

//! Runie Provider - Concrete LLM provider implementations

pub mod mock;
pub mod model;
pub mod openai;
pub mod config;

pub use mock::MockProvider;
pub use model::{ModelId, ModelRegistry};
pub use openai::OpenAiProvider;
pub use config::Config;

use anyhow::Result;
use runie_core::provider::{Message, Provider, ResponseChunk};

/// Runtime provider selection — closed enum for static dispatch.
pub enum AnyProvider {
    Mock(MockProvider),
    OpenAi(OpenAiProvider),
}

impl AnyProvider {
    fn build(provider: &str, model: &str) -> Self {
        let config = Config::load();
        Self::build_with_config(provider, model, &config)
    }

    fn build_with_config(provider: &str, model: &str, config: &Config) -> Self {
        if let Some(custom) = config.model_providers.get(provider) {
            return Self::OpenAi(OpenAiProvider::new(
                custom.api_key.clone(),
                model,
            ).with_base_url(custom.base_url.clone()));
        }
        match provider {
            "openai" => {
                let key = std::env::var("OPENAI_API_KEY").unwrap_or_default();
                if key.is_empty() {
                    eprintln!("Warning: OPENAI_API_KEY not set, falling back to mock");
                    Self::Mock(MockProvider::default())
                } else {
                    Self::OpenAi(OpenAiProvider::new(key, model))
                }
            }
            _ => {
                if std::env::var("RUNIE_MOCK_DELAY").is_ok() {
                    Self::Mock(MockProvider::with_delay(500, 3000))
                } else {
                    Self::Mock(MockProvider::default())
                }
            }
        }
    }

    pub fn new(provider: &str, model: &str) -> Self {
        Self::build(provider, model)
    }

    pub fn from_env() -> Self {
        let config = Config::load();
        Self::from_config(&config, config.default_model().unwrap_or("echo"))
    }

    pub fn from_config(config: &Config, model: &str) -> Self {
        let provider = if model.contains('/') {
            model.split('/').next().unwrap_or("mock")
        } else {
            config.provider.as_deref().unwrap_or("mock")
        };
        Self::build_with_config(provider, model, config)
    }

    pub fn switch(&mut self, provider: &str, model: &str) {
        *self = Self::build(provider, model);
    }

    pub fn name(&self) -> &'static str {
        match self {
            AnyProvider::Mock(_) => "mock",
            AnyProvider::OpenAi(_) => "openai",
        }
    }

    pub fn model(&self) -> String {
        match self {
            AnyProvider::Mock(_) => "echo".to_string(),
            AnyProvider::OpenAi(p) => p.model().to_string(),
        }
    }
}

impl Provider for AnyProvider {
    async fn generate<F>(&self, messages: Vec<Message>, on_chunk: F) -> Result<()>
    where
        F: FnMut(ResponseChunk) + Send,
    {
        match self {
            AnyProvider::Mock(p) => p.generate(messages, on_chunk).await,
            AnyProvider::OpenAi(p) => p.generate(messages, on_chunk).await,
        }
    }
}

