//! Shared Event Bus with typed channels per actor
//!
//! Architecture:
//!   - Each actor has its own typed channel
//!   - Events are tagged as domain (persisted) or ephemeral (not persisted)
//!   - Subscribers can filter by event type and tag

use std::collections::HashMap;
use std::sync::mpsc::{channel, Receiver, Sender};
use std::sync::{Arc, Mutex};

/// Event tag determines persistence behavior
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EventTag {
    /// Domain events are persisted to session history
    Domain,
    /// Ephemeral events are not persisted
    Ephemeral,
}

/// Trait for event types that can be published on the bus
pub trait BusEvent: Clone + Send + 'static {
    /// Returns the event's tag (domain vs ephemeral)
    fn tag(&self) -> EventTag;
}

/// Domain events — persisted to session
#[derive(Debug, Clone)]
pub enum DomainEvent {
    Submit { content: String },
    SpawnAgent,
    AgentThinking { id: String },
    AgentThoughtDone { id: String },
    AgentResponse { id: String, content: String },
    AgentTurnComplete { id: String, duration_secs: f64 },
    AgentToolStart { id: String, name: String },
    AgentToolEnd { id: String, name: String, duration_secs: f64, output: String },
    AgentDone { id: String },
    AgentError { id: String, message: String },
    SwitchModel { provider: String, model: String },
    FollowUp { content: String },
    ToolRegistered { name: String },
}

impl BusEvent for DomainEvent {
    fn tag(&self) -> EventTag {
        EventTag::Domain
    }
}

/// Ephemeral events — not persisted
#[derive(Debug, Clone)]
pub enum EphemeralEvent {
    Input(char),
    Backspace,
    CursorLeft,
    CursorRight,
    CursorStart,
    CursorEnd,
    DeleteWord,
    DeleteToEnd,
    DeleteToStart,
    KillChar,
    HistoryPrev,
    HistoryNext,
    Undo,
    Redo,
    CursorWordLeft,
    CursorWordRight,
    Paste(String),
    ScrollUp,
    ScrollDown,
    ToggleExpand,
    Abort,
}

impl BusEvent for EphemeralEvent {
    fn tag(&self) -> EventTag {
        EventTag::Ephemeral
    }
}

/// Unified event envelope for the bus
#[derive(Debug, Clone)]
pub enum BusEventEnvelope {
    Domain(DomainEvent),
    Ephemeral(EphemeralEvent),
}

impl BusEventEnvelope {
    pub fn tag(&self) -> EventTag {
        match self {
            BusEventEnvelope::Domain(_) => EventTag::Domain,
            BusEventEnvelope::Ephemeral(_) => EventTag::Ephemeral,
        }
    }
}

/// Actor identifier for typed channels
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ActorId {
    AgentLoop,
    QueueAgent,
    SessionManager,
    ConfigAgent,
    ToolActor { name: String },
    RenderActor,
    InputActor,
}

impl std::fmt::Display for ActorId {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            ActorId::AgentLoop => write!(f, "AgentLoop"),
            ActorId::QueueAgent => write!(f, "QueueAgent"),
            ActorId::SessionManager => write!(f, "SessionManager"),
            ActorId::ConfigAgent => write!(f, "ConfigAgent"),
            ActorId::ToolActor { name } => write!(f, "ToolActor({})", name),
            ActorId::RenderActor => write!(f, "RenderActor"),
            ActorId::InputActor => write!(f, "InputActor"),
        }
    }
}

/// Typed channel endpoint for an actor
#[derive(Debug)]
pub struct ActorChannel<T> {
    pub tx: Sender<T>,
    pub rx: Receiver<T>,
}

impl<T: Clone + Send + 'static> ActorChannel<T> {
    /// Create a new typed channel pair
    pub fn new() -> Self {
        let (tx, rx) = channel();
        Self { tx, rx }
    }

    /// Try to receive a message without blocking
    pub fn try_recv(&self) -> Result<T, std::sync::mpsc::TryRecvError> {
        self.rx.try_recv()
    }

    /// Receive a message, blocking until available
    pub fn recv(&self) -> Result<T, std::sync::mpsc::RecvError> {
        self.rx.recv()
    }
}

impl<T: Clone + Send + 'static> Default for ActorChannel<T> {
    fn default() -> Self {
        Self::new()
    }
}

/// Subscription filter for event filtering
#[derive(Debug, Clone, Default)]
pub struct SubscriptionFilter {
    pub include_domain: bool,
    pub include_ephemeral: bool,
}

impl SubscriptionFilter {
    pub fn all() -> Self {
        Self {
            include_domain: true,
            include_ephemeral: true,
        }
    }

    pub fn domain_only() -> Self {
        Self {
            include_domain: true,
            include_ephemeral: false,
        }
    }

    pub fn ephemeral_only() -> Self {
        Self {
            include_domain: false,
            include_ephemeral: true,
        }
    }

    pub fn matches(&self, event: &BusEventEnvelope) -> bool {
        match event {
            BusEventEnvelope::Domain(_) if !self.include_domain => false,
            BusEventEnvelope::Ephemeral(_) if !self.include_ephemeral => false,
            _ => true,
        }
    }
}

/// Thread-safe broadcast channel for inter-actor communication
#[derive(Clone)]
pub struct BroadcastChannel {
    tx: Sender<BusEventEnvelope>,
    rx: Arc<Mutex<Receiver<BusEventEnvelope>>>,
}

impl Default for BroadcastChannel {
    fn default() -> Self {
        Self::new()
    }
}

impl BroadcastChannel {
    /// Create a new broadcast channel
    pub fn new() -> Self {
        let (tx, rx) = channel();
        Self {
            tx,
            rx: Arc::new(Mutex::new(rx)),
        }
    }

    /// Send an event to all subscribers
    pub fn send(&self, event: BusEventEnvelope) -> Result<(), std::sync::mpsc::SendError<BusEventEnvelope>> {
        self.tx.send(event)
    }

    /// Try to receive without blocking
    pub fn try_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::TryRecvError> {
        self.rx.lock().unwrap().try_recv()
    }

    /// Receive, blocking until available
    pub fn recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::RecvError> {
        self.rx.lock().unwrap().recv()
    }

    /// Get a cloned receiver for subscribing
    pub fn receiver(&self) -> Arc<Mutex<Receiver<BusEventEnvelope>>> {
        self.rx.clone()
    }
}

/// Shared event bus for inter-actor communication
#[derive(Clone, Default)]
pub struct EventBus {
    /// Broadcast channel for events
    broadcast: BroadcastChannel,
    /// Subscription filters per actor
    subscriptions: Arc<Mutex<HashMap<ActorId, SubscriptionFilter>>>,
}

impl EventBus {
    /// Create a new event bus
    pub fn new() -> Self {
        Self::default()
    }

    /// Subscribe an actor to specific event types
    pub fn subscribe(&self, actor: ActorId, filter: SubscriptionFilter) {
        self.subscriptions.lock().unwrap().insert(actor, filter);
    }

    /// Unsubscribe an actor
    pub fn unsubscribe(&self, actor: &ActorId) {
        self.subscriptions.lock().unwrap().remove(actor);
    }

    /// Publish an event to all subscribed actors
    pub fn publish(&self, event: BusEventEnvelope) {
        let _ = self.broadcast.send(event);
    }

    /// Publish a domain event
    pub fn publish_domain(&self, event: DomainEvent) {
        self.publish(BusEventEnvelope::Domain(event));
    }

    /// Publish an ephemeral event
    pub fn publish_ephemeral(&self, event: EphemeralEvent) {
        self.publish(BusEventEnvelope::Ephemeral(event));
    }

    /// Receive from the broadcast channel
    pub fn broadcast_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::RecvError> {
        self.broadcast.recv()
    }

    /// Try to receive from the broadcast channel
    pub fn broadcast_try_recv(&self) -> Result<BusEventEnvelope, std::sync::mpsc::TryRecvError> {
        self.broadcast.try_recv()
    }

    /// Get the broadcast receiver
    pub fn broadcast_receiver(&self) -> Arc<Mutex<Receiver<BusEventEnvelope>>> {
        self.broadcast.receiver()
    }

    /// Register a typed channel for an actor
    pub fn register<T: Clone + Send + 'static>(&self, _actor: ActorId) -> ActorChannel<T> {
        ActorChannel::new()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_domain_events_are_tagged() {
        let event = DomainEvent::Submit { content: "test".into() };
        assert_eq!(event.tag(), EventTag::Domain);
    }

    #[test]
    fn test_ephemeral_events_are_tagged() {
        let event = EphemeralEvent::ScrollUp;
        assert_eq!(event.tag(), EventTag::Ephemeral);
    }

    #[test]
    fn test_event_envelope_tag() {
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        assert_eq!(domain.tag(), EventTag::Domain);

        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::Input('a'));
        assert_eq!(ephemeral.tag(), EventTag::Ephemeral);
    }

    #[test]
    fn test_actor_channel_basic() {
        let channel: ActorChannel<String> = ActorChannel::new();
        channel.tx.send("hello".to_string()).unwrap();
        let received = channel.rx.recv().unwrap();
        assert_eq!(received, "hello");
    }

    #[test]
    fn test_subscription_filter_domain_only() {
        let filter = SubscriptionFilter::domain_only();
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp);
        assert!(filter.matches(&domain));
        assert!(!filter.matches(&ephemeral));
    }

    #[test]
    fn test_subscription_filter_ephemeral_only() {
        let filter = SubscriptionFilter::ephemeral_only();
        let domain = BusEventEnvelope::Domain(DomainEvent::Submit { content: "test".into() });
        let ephemeral = BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp);
        assert!(!filter.matches(&domain));
        assert!(filter.matches(&ephemeral));
    }

    #[test]
    fn test_event_bus_publish_and_broadcast() {
        let bus = EventBus::new();
        bus.publish_domain(DomainEvent::Submit { content: "hello".into() });

        let received = bus.broadcast_recv().unwrap();
        match received {
            BusEventEnvelope::Domain(DomainEvent::Submit { content }) => {
                assert_eq!(content, "hello");
            }
            _ => panic!("Expected domain Submit event"),
        }
    }

    #[test]
    fn test_event_bus_ephemeral_publish() {
        let bus = EventBus::new();
        bus.publish_ephemeral(EphemeralEvent::ScrollUp);

        let received = bus.broadcast_recv().unwrap();
        match received {
            BusEventEnvelope::Ephemeral(EphemeralEvent::ScrollUp) => {}
            _ => panic!("Expected ephemeral ScrollUp event"),
        }
    }

    #[test]
    fn test_actor_id_display() {
        assert_eq!(ActorId::AgentLoop.to_string(), "AgentLoop");
        assert_eq!(ActorId::SessionManager.to_string(), "SessionManager");
        assert_eq!(
            ActorId::ToolActor { name: "bash".into() }.to_string(),
            "ToolActor(bash)"
        );
    }

    #[test]
    fn test_event_bus_clone() {
        let bus1 = EventBus::new();
        let bus2 = bus1.clone();
        bus1.publish_domain(DomainEvent::SpawnAgent);
        assert!(bus2.broadcast_try_recv().is_ok());
    }

    #[test]
    fn test_broadcast_channel_arc_mutex() {
        let channel = BroadcastChannel::new();
        let receiver = channel.receiver();
        channel.send(BusEventEnvelope::Domain(DomainEvent::SpawnAgent)).unwrap();
        assert!(receiver.lock().unwrap().recv().is_ok());
    }
}

use base64::Engine;
use std::path::Path;

#[derive(Debug, Clone)]
pub struct FileRef {
    pub path: String,
    pub text: String,
    pub is_image: bool,
}

pub fn find_files(pattern: &str, base: &str, limit: usize) -> Vec<String> {
    find_files_deep(pattern, base, limit)
}

pub fn find_files_shallow(pattern: &str, base: &str, limit: usize) -> Vec<String> {
    let mut results = Vec::new();
    let pat_lower = pattern.to_lowercase();
    let Ok(entries) = std::fs::read_dir(base) else { return results };
    for entry in entries.flatten() {
        if results.len() >= limit { break; }
        let name = entry.file_name().to_string_lossy().to_string();
        if name.to_lowercase().contains(&pat_lower) {
            results.push(name);
        }
    }
    results.sort();
    results
}

pub fn find_files_deep(pattern: &str, base: &str, limit: usize) -> Vec<String> {
    let mut results = Vec::new();
    if pattern.is_empty() || pattern == "*" {
        if let Ok(entries) = std::fs::read_dir(base) {
            for entry in entries.flatten().take(limit) {
                let name = entry.file_name().to_string_lossy().to_string();
                results.push(name);
            }
        }
        return results;
    }
    let is_glob = pattern.contains('*') || pattern.contains('?');
    if is_glob {
        collect_deep(base, &mut results, limit, &|name, path| {
            glob_matches(name, pattern) || glob_matches(path, pattern)
        });
    } else {
        let pat_lower = pattern.to_lowercase();
        collect_deep(base, &mut results, limit, &|name, path| {
            name.to_lowercase().contains(&pat_lower) || path.to_lowercase().contains(&pat_lower)
        });
    }
    results
}

fn collect_deep<F>(dir: &str, out: &mut Vec<String>, limit: usize, matches: &F)
where
    F: Fn(&str, &str) -> bool,
{
    if out.len() >= limit {
        return;
    }
    let Ok(entries) = std::fs::read_dir(dir) else { return };
    for entry in entries.flatten() {
        if out.len() >= limit {
            break;
        }
        let name = entry.file_name().to_string_lossy().to_string();
        let path = entry.path().to_string_lossy().to_string();
        let meta = entry.metadata();
        let is_dir = meta.as_ref().map(|m| m.is_dir()).unwrap_or(false);
        if matches(&name, &path) {
            out.push(path.clone());
        }
        if is_dir && !name.starts_with('.') && name != "target" {
            collect_deep(&path, out, limit, matches);
        }
    }
}

fn glob_matches(name: &str, pattern: &str) -> bool {
    let name_lower = name.to_lowercase();
    let pat_lower = pattern.to_lowercase();
    if pat_lower.starts_with("*.") {
        let ext = &pat_lower[2..];
        name_lower.ends_with(&format!(".{}", ext))
    } else if pat_lower.contains('*') || pat_lower.contains('?') {
        name_lower.contains(&pat_lower.replace("*", "").replace("?", ""))
    } else {
        name_lower.contains(&pat_lower)
    }
}

pub fn is_image_file(path: &str) -> bool {
    let ext = Path::new(path)
        .extension()
        .and_then(|e| e.to_str())
        .unwrap_or("")
        .to_lowercase();
    matches!(ext.as_str(), "png" | "jpg" | "jpeg" | "gif" | "webp" | "bmp" | "svg")
}

pub fn read_file_ref(path: &str) -> Result<FileRef, String> {
    let is_image = is_image_file(path);
    let (text, is_image) = if is_image {
        let bytes = std::fs::read(path)
            .map_err(|e| format!("Error reading {}: {}", path, e))?;
        (base64::engine::general_purpose::STANDARD.encode(&bytes), true)
    } else {
        let text = std::fs::read_to_string(path)
            .map_err(|e| format!("Error reading {}: {}", path, e))?;
        (text, false)
    };
    Ok(FileRef { path: path.to_string(), text, is_image })
}

pub fn complete_at_ref(input: &str, base: &str, limit: usize) -> Vec<String> {
    let query = input.split('@').last().unwrap_or("");
    find_files_shallow(query, base, limit)
}

pub fn insert_at_ref(input: &str, selected: &str) -> String {
    if let Some(pos) = input.rfind('@') {
        let prefix = &input[..pos];
        format!("{}[{}]", prefix, selected)
    } else {
        input.to_string()
    }
}

//! View — renders Snapshot to terminal via ratatui
//!
//! Architecture: the event loop builds immutable Snapshots;
//! the render actor draws them. No state mutations, no blocking
//! I/O, no caching — pure functions from Snapshot to Frame.
//!
//! DESIGN SYSTEM RULE: all colors, glyphs, and styles come from
//! crate::theme only. No literals, no hardcoded values.

use ratatui::{
    layout::{Constraint, Direction, Layout, Rect},
    style::{Color, Style},
    text::{Line, Span},
    widgets::{Block, Borders, Paragraph, Scrollbar, ScrollbarOrientation, ScrollbarState, Wrap},
    Frame,
};

fn vstack(area: Rect, heights: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Vertical).constraints(heights).split(area).to_vec()
}

fn hstack(area: Rect, widths: &[Constraint]) -> Vec<Rect> {
    Layout::default().direction(Direction::Horizontal).constraints(widths).split(area).to_vec()
}

use runie_core::{Element, Snapshot};

use crate::markdown::{extract_code_blocks, md_to_spans, parse_inline_markdown, parse_inline_markdown_with_color, CodeBlock};
use runie_core::format_timestamp;
use crate::theme::{
    C, GLYPH_USER, GLYPH_AGENT, GLYPH_TOOL, GLYPH_INDENT,
    GLYPH_SELECTED, GLYPH_UNSELECTED, PANEL_CHAT, PANEL_INPUT,
    SCROLLBAR_TRACK, SCROLLBAR_THUMB, INDICATOR_COLLAPSED,
    code_header_label, thinking_line, tool_running_line, tool_done_header,
    tool_summary_line, turn_complete_line, thought_summary_line,
    style_user, style_agent, style_thought, style_thinking, style_thought_summary,
    style_tool_running, style_tool_header, style_tool_output, style_tool_summary,
    style_turn_complete, style_empty_state, style_timestamp, style_status_idle,
    style_status_active, style_border, style_border_flash, style_code_block,
    style_code_header, style_input_cursor, style_placeholder, style_hint,
    style_popup_selected, style_popup_unselected, style_popup_border,
};

/// Draw a Snapshot to the terminal. Pure function — no mutable state.
pub fn draw_snapshot(f: &mut Frame, snap: &Snapshot) {
    let c = vstack(f.area(), &[
        Constraint::Min(3),
        Constraint::Length(1),
        Constraint::Length(3),
        Constraint::Length(1),
    ]);
    messages(f, snap, c[0]);
    status(f, snap, c[1]);
    input(f, snap, c[2]);
    hints(f, snap, c[3]);
    at_suggestions(f, snap);
}

/// Legacy entry point for code that still builds AppState directly.
pub fn view(f: &mut Frame, state: &mut runie_core::AppState) {
    state.ensure_fresh();
    let snap = state.snapshot();
    draw_snapshot(f, &snap);
}

fn status(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let tokens: usize = snap.elements.iter().map(|e| estimate_element_tokens(e)).sum();
    let left_text = build_status_text(snap);
    let right_text = format!("{} tok", tokens);

    let h = hstack(area, &[
        Constraint::Min(0),
        Constraint::Length(right_text.len() as u16),
    ]);

    let status_style = if snap.turn_active {
        style_status_active()
    } else {
        style_status_idle()
    };

    f.render_widget(Paragraph::new(left_text).style(status_style), h[0]);
    f.render_widget(Paragraph::new(right_text).style(style_timestamp()), h[1]);
}

fn build_status_text(snap: &Snapshot) -> String {
    let mut parts = Vec::new();
    parts.push(format!("{}/{}", snap.provider, snap.model));
    if snap.turn_active {
        if let Some(elapsed) = snap.turn_elapsed_secs {
            parts.push(runie_core::labels::action_text(
                snap.spinner_frame, "Working", elapsed,
            ));
        } else {
            parts.push(format!("{} Working...", snap.spinner_frame));
        }
    }
    parts.join(" · ")
}

fn messages(f: &mut Frame, snap: &Snapshot, area: Rect) {
    if snap.elements.is_empty() {
        render_empty_state(f, area);
        return;
    }
    render_message_content(f, snap, area);
}

fn render_empty_state(f: &mut Frame, area: Rect) {
    let hint = Line::from("Type a message to start...").style(style_empty_state());
    f.render_widget(Paragraph::new(hint), area);
}

fn render_message_content(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let height = area.height as usize;
    let total_lines = snap.total_lines;
    if height == 0 || total_lines == 0 {
        return;
    }

    let show_bar = total_lines > height;
    let content_width = if show_bar {
        area.width.saturating_sub(1)
    } else {
        area.width
    };

    let h = hstack(area, &[Constraint::Length(content_width), Constraint::Min(0)]);
    let lines = build_lines(snap);
    let offset = snap.scroll_offset(height);
    f.render_widget(
        Paragraph::new(lines)
            .scroll((offset, 0))
            .wrap(Wrap { trim: false }),
        h[0],
    );

    if show_bar {
        render_scrollbar(f, area, total_lines, offset, height);
    }
}

fn build_lines(snap: &Snapshot) -> Vec<Line<'_>> {
    let mut lines = Vec::with_capacity(snap.total_lines);
    for elem in &snap.elements {
        lines.extend(to_lines(elem, snap.spinner_frame));
    }
    lines
}

fn render_scrollbar(f: &mut Frame, area: Rect, total: usize, offset: u16, height: usize) {
    let scrollbar = Scrollbar::default()
        .orientation(ScrollbarOrientation::VerticalRight)
        .begin_symbol(None)
        .end_symbol(None)
        .track_symbol(Some(SCROLLBAR_TRACK))
        .thumb_symbol(SCROLLBAR_THUMB);

    let mut state = ScrollbarState::new(total)
        .position(offset as usize)
        .viewport_content_length(height);
    f.render_stateful_widget(scrollbar, area, &mut state);
}

fn to_lines<'a>(elem: &'a Element, _spinner_frame: char) -> Vec<Line<'a>> {
    use runie_core::Element::*;
    match elem {
        Spacer { .. } => vec![Line::from("")],
        UserMessage { content, timestamp } => render_message(content, *timestamp, GLYPH_USER, C.fg_bright),
        AgentMessage { content, timestamp } => render_agent_message(content, *timestamp),
        Thinking { started, .. } => vec![Line::from(
            thinking_line(started.elapsed().as_secs_f64())
        ).style(style_thinking())],
        ThoughtSummary { content, .. } => vec![Line::from(
            thought_summary_line(content.lines().next().unwrap_or(content))
        ).style(style_thought_summary())],
        ThoughtMarker { content, .. } => render_thought_marker(content),
        ToolRunning { name, started, .. } => vec![Line::from(
            tool_running_line(name, started.elapsed().as_secs_f64())
        ).style(style_tool_running())],
        ToolDone { name, duration_secs, output, .. } => render_tool_done(name, *duration_secs, output),
        ToolSummary { name, duration_secs, .. } => vec![Line::from(
            tool_summary_line(name, *duration_secs)
        ).style(style_tool_summary())],
        TurnComplete { duration_secs, .. } => vec![Line::from(
            turn_complete_line(*duration_secs)
        ).style(style_turn_complete())],
    }
}

fn render_message(content: &str, timestamp: f64, first_prefix: &'static str, base_color: Color) -> Vec<Line<'static>> {
    let mut lines = Vec::new();
    let ts_str = format_timestamp(timestamp);
    let base_style = if base_color == C.fg_bright { style_user() } else { style_agent() };
    for (i, line) in content.lines().enumerate() {
        let prefix = if i == 0 { first_prefix } else { GLYPH_INDENT };
        let ts = format!(" {:>5}", ts_str);
        let mut spans = vec![Span::styled(prefix, base_style)];
        spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, base_color)));
        spans.push(Span::styled(ts, style_timestamp()));
        lines.push(Line::from(spans));
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", first_prefix, ts_str)).style(base_style));
    }
    lines
}

fn render_agent_message(content: &str, timestamp: f64) -> Vec<Line<'static>> {
    let blocks = extract_code_blocks(content);
    let mut lines = Vec::new();
    let mut is_first = true;
    let ts_str = format_timestamp(timestamp);

    for block in blocks {
        match block {
            CodeBlock::Text(text) => {
                for line in text.lines() {
                    lines.push(render_msg_line(line, timestamp, is_first));
                    is_first = false;
                }
            }
            CodeBlock::Code { lang, content } => {
                lines.push(render_code_header(&lang, is_first));
                is_first = false;
                for line in content.lines() {
                    let text = format!("{}{} {:>5}", GLYPH_INDENT, line, ts_str);
                    lines.push(Line::from(text).style(style_code_block()));
                }
            }
        }
    }
    if lines.is_empty() {
        lines.push(Line::from(format!("{}{:>5}", GLYPH_AGENT, ts_str)).style(style_agent()));
    }
    lines
}

fn render_code_header(lang: &str, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    Line::from(code_header_label(prefix, lang)).style(style_code_header())
}

fn render_msg_line(line: &str, timestamp: f64, is_first: bool) -> Line<'static> {
    let prefix = if is_first { GLYPH_AGENT } else { GLYPH_INDENT };
    let ts = format!(" {:>5}", format_timestamp(timestamp));
    let mut spans = vec![Span::styled(prefix.to_string(), style_agent())];
    spans.extend(md_to_spans(&parse_inline_markdown_with_color(line, C.fg)));
    spans.push(Span::styled(ts, style_timestamp()));
    Line::from(spans)
}

fn render_thought_marker(content: &str) -> Vec<Line<'static>> {
    content.lines()
        .map(|line| Line::from(line.to_string()).style(style_thought()))
        .collect()
}

fn render_tool_done(name: &str, duration_secs: f64, output: &str) -> Vec<Line<'static>> {
    let mut lines = vec![Line::from(tool_done_header(name, duration_secs))
        .style(style_tool_header())];
    if !output.is_empty() {
        for line in output.lines() {
            lines.push(Line::from(line.to_string()).style(style_tool_output()));
        }
    }
    lines
}

fn input(f: &mut Frame, snap: &Snapshot, area: Rect) {
    let border_style = if snap.input_flash > 0 {
        style_border_flash()
    } else {
        style_border()
    };
    let block = Block::default()
        .borders(Borders::ALL)
        .title(PANEL_INPUT)
        .border_style(border_style);
    let inner = block.inner(area);

    let spans = build_input_spans(snap);
    f.render_widget(Paragraph::new(Line::from(spans)).block(block), area);

    let cursor_x = inner.x + (GLYPH_USER.len() + snap.cursor_pos.min(snap.input.len())) as u16;
    f.set_cursor_position((cursor_x, inner.y));
}

fn build_input_spans(snap: &Snapshot) -> Vec<Span<'_>> {
    if snap.input.is_empty() && !snap.placeholder.is_empty() {
        return vec![
            Span::styled(GLYPH_USER, style_user()),
            Span::styled(snap.placeholder.clone(), style_placeholder()),
        ];
    }
    let cursor_pos = snap.cursor_pos.min(snap.input.len());
    let before = &snap.input[..cursor_pos];
    let (at_cursor, after) = if cursor_pos < snap.input.len() {
        let c = snap.input[cursor_pos..].chars().next().unwrap();
        let char_len = c.len_utf8();
        (c, &snap.input[cursor_pos + char_len..])
    } else {
        (' ', "")
    };
    vec![
        Span::styled(GLYPH_USER, style_user()),
        Span::styled(before, style_user()),
        Span::styled(at_cursor.to_string(), style_input_cursor()),
        Span::styled(after, style_user()),
    ]
}

fn hints(f: &mut Frame, _snap: &Snapshot, area: Rect) {
    let hints_text = "Ctrl+Shift+E=expand/collapse | Alt+Enter=follow-up | Esc=clear | Ctrl+C=quit";
    f.render_widget(Paragraph::new(hints_text).style(style_hint()), area);
}

fn at_suggestions(f: &mut Frame, snap: &Snapshot) {
    let suggestions = match &snap.at_suggestions {
        Some(s) if !s.is_empty() => s,
        _ => return,
    };
    let selected = snap.at_selected.unwrap_or(0).min(suggestions.len().saturating_sub(1));
    let area = f.area();
    let display_count = suggestions.len().min(8) as u16;
    let max_height = display_count + 4;
    let popup_area = Rect {
        x: area.x + 1,
        y: area.y + area.height.saturating_sub(4 + max_height),
        width: area.width.saturating_sub(2).max(20),
        height: max_height,
    };
    let mut lines: Vec<Line> = suggestions
        .iter()
        .take(8)
        .enumerate()
        .map(|(i, s)| {
            let prefix = if i == selected { GLYPH_SELECTED } else { GLYPH_UNSELECTED };
            let style = if i == selected { style_popup_selected() } else { style_popup_unselected() };
            Line::from(format!("{}{}", prefix, s)).style(style)
        })
        .collect();
    lines.push(Line::from(""));
    lines.push(
        Line::from("Tab=cycle Enter=insert Esc=close").style(style_hint()),
    );
    let block = Block::default()
        .borders(Borders::ALL)
        .title(format!(" @ files ({}) ", suggestions.len()))
        .border_style(style_popup_border());
    f.render_widget(Paragraph::new(lines).block(block), popup_area);
}

fn estimate_element_tokens(elem: &Element) -> usize {
    use runie_core::Element::*;
    match elem {
        UserMessage { content, .. }
        | AgentMessage { content, .. }
        | ThoughtMarker { content, .. } => content.len() / 4,
        Thinking { .. }
        | ThoughtSummary { .. }
        | ToolSummary { .. }
        | TurnComplete { .. } => 10,
        ToolRunning { .. } => 10,
        ToolDone { output, .. } => output.len() / 4 + 10,
        Spacer { .. } => 0,
    }
}

//! Model — Application State (mutable borrow, no cloning per event)
use crate::snapshot::Snapshot;
use crate::ui::elements::Element;


const SPINNER_CHARS: &[char] = &['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠹', '⠸', '⠴', '⠼'];
const SPINNER_FRAMES: u32 = 12;

/// A viewport into the element cache — elements plus how many
/// lines to skip from the top of the first element.
#[derive(Clone, Copy)]
pub struct VisibleRegion<'a> {
    pub elements: &'a [Element],
    pub skip_lines: usize,
}

#[derive(Clone, Debug, PartialEq, Eq)]
pub enum QueuedMessageKind {
    Steering,
    FollowUp,
}

#[derive(Clone, Debug)]
pub struct QueuedMessage {
    pub content: String,
    pub kind: QueuedMessageKind,
}

#[derive(Clone)]
pub struct AppState {
    pub messages: Vec<ChatMessage>,
    pub input: String,
    /// Cursor position in input (0 = before first char)
    pub cursor_pos: usize,
    pub streaming: bool,
    pub scroll: usize,
    pub thinking_started_at: Option<std::time::Instant>,
    pub request_queue: std::collections::VecDeque<(String, String)>,
    pub message_queue: Vec<QueuedMessage>,
    pub next_id: u64,
    pub current_request_id: Option<String>,
    pub turn_started_at: Option<std::time::Instant>,
    pub current_tool_name: Option<String>,
    pub tool_started_at: Option<std::time::Instant>,
    pub intermediate_step_count: usize,
    pub animation_frame: u32,
    pub turn_active: bool,
    pub current_action: Option<String>,
    pub current_provider: String,
    pub current_model: String,

    /// Number of commands sent to agent but not yet completed
    pub inflight: usize,
    /// Monotonic counter — increments on every snapshot sent to render actor
    pub render_generation: u64,
    /// @-ref file lookup suggestions
    pub at_suggestions: Option<Vec<String>>,
    /// Selected index in @-ref suggestions
    pub at_selected: Option<usize>,
    /// Last @-ref query to avoid redundant filesystem calls
    pub last_at_query: Option<String>,
    /// Global collapse flag — when true, ALL thoughts/tools render collapsed.
    /// New elements automatically respect this setting.
    pub all_collapsed: bool,
    pub(crate) thought_seq: u64,
    pub(crate) input_history: Vec<String>,
    pub(crate) history_pos: Option<usize>,
    pub(crate) undo_stack: Vec<(String, usize)>,
    pub(crate) redo_stack: Vec<(String, usize)>,
    pub input_flash: u8,
    pub placeholder: String,
    element_count: usize,
    elements_cache: Vec<Element>,
    line_counts: Vec<usize>,
    total_lines: usize,
    dirty: bool,
    message_gen: u64,
    cached_gen: u64,
}

impl Default for AppState {
    fn default() -> Self {
        Self {
            messages: Vec::new(), input: String::new(), cursor_pos: 0,
            streaming: false, scroll: 0, thinking_started_at: None,
            request_queue: std::collections::VecDeque::new(),
            message_queue: Vec::new(), next_id: 0,
            current_request_id: None, turn_started_at: None,
            current_tool_name: None, tool_started_at: None,
            intermediate_step_count: 0, animation_frame: 0,
            turn_active: false, current_action: None,
            current_provider: "mock".into(), current_model: "echo".into(),
            inflight: 0, render_generation: 0,
            at_suggestions: None, at_selected: None, last_at_query: None,
            all_collapsed: false, thought_seq: 0,
            input_history: Vec::new(), history_pos: None,
            undo_stack: Vec::new(), redo_stack: Vec::new(),
            input_flash: 0, placeholder: "Type a message to start...".into(),
            element_count: 0, elements_cache: Vec::new(),
            line_counts: Vec::new(), total_lines: 0,
            dirty: true, message_gen: 1, cached_gen: 0,
        }
    }
}

impl AppState {
    pub fn thinking_elapsed_secs(&self) -> Option<f64> {
        self.thinking_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn turn_elapsed_secs(&self) -> Option<f64> {
        self.turn_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    pub fn tool_elapsed_secs(&self) -> Option<f64> {
        self.tool_started_at.map(|t| t.elapsed().as_secs_f64())
    }

    /// Braille spinner frame (12-frame cycle)
    pub fn spinner_frame(&self) -> char {
        SPINNER_CHARS[(self.animation_frame % SPINNER_FRAMES) as usize]
    }

    pub fn next_id(&mut self) -> String {
        let id = format!("req.{}", self.next_id);
        self.next_id += 1;
        id
    }

    pub(crate) fn mark_dirty(&mut self) {
        self.dirty = true;
    }

    pub(crate) fn messages_changed(&mut self) {
        self.message_gen = self.message_gen.wrapping_add(1);
        self.dirty = true;
    }

    pub fn cache_generation(&self) -> u64 {
        self.message_gen
    }

    /// Rebuild cache only when messages changed — O(n) but gated
    pub fn ensure_fresh(&mut self) {
        if self.dirty && self.message_gen != self.cached_gen {
            self.elements_cache = crate::ui::LazyCache::rebuild(self);
            self.element_count = self.elements_cache.len();
            self.line_counts = self.elements_cache.iter().map(|e| e.line_count()).collect();
            self.total_lines = self.line_counts.iter().sum();
            self.cached_gen = self.message_gen;
        }
        self.dirty = false;
    }

    /// Visible elements slice — O(1), zero allocation
    pub fn visible(&self, skip: usize, take: usize) -> &[Element] {
        if self.elements_cache.is_empty() {
            return &[];
        }
        let start = skip.min(self.element_count).min(self.elements_cache.len());
        let end = (start + take).min(self.element_count).min(self.elements_cache.len());
        &self.elements_cache[start..end]
    }

    pub fn count(&self) -> usize {
        self.element_count.max(self.elements_cache.len())
    }

    pub fn element_count(&self) -> usize {
        self.element_count
    }

    pub fn total_lines(&self) -> usize {
        self.total_lines
    }

    pub fn elements_cache(&self) -> &[Element] {
        &self.elements_cache
    }

    pub fn tick_animation(&mut self) {
        let mut changed = false;
        if self.turn_active {
            self.animation_frame = self.animation_frame.wrapping_add(1);
            changed = true;
        }
        if self.input_flash > 0 {
            self.input_flash -= 1;
            changed = true;
        }
        if changed {
            self.dirty = true;
        }
    }

    /// Build an immutable Snapshot for the render actor.
    /// The event loop calls this after ensure_fresh(); the render
    /// actor receives it via channel and draws without touching state.
    pub fn snapshot(&self) -> Snapshot {
        Snapshot {
            elements: self.elements_cache.clone(),
            line_counts: self.line_counts.clone(),
            total_lines: self.total_lines,
            input: self.input.clone(),
            cursor_pos: self.cursor_pos,
            hint_text: self.hint_text(),
            at_suggestions: self.at_suggestions.clone(),
            at_selected: self.at_selected,
            turn_active: self.turn_active,
            input_flash: self.input_flash,
            placeholder: self.placeholder.clone(),
            spinner_frame: self.spinner_frame(),
            scroll: self.scroll,
            turn_elapsed_secs: self.turn_elapsed_secs(),
            provider: self.current_provider.clone(),
            model: self.current_model.clone(),
        }
    }

    pub fn is_dirty(&self) -> bool {
        self.dirty
    }

    pub fn scroll_offset(&self, visible_height: usize) -> u16 {
        let max_scroll = self.total_lines.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        max_scroll.saturating_sub(scroll).min(u16::MAX as usize) as u16
    }

    pub fn scrollbar_metrics(&self, visible_height: usize) -> (usize, usize) {
        let total = self.total_lines;
        if total <= visible_height || visible_height == 0 {
            return (0, 0);
        }
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);
        let position = max_scroll.saturating_sub(scroll);
        let track = visible_height;
        let thumb = (visible_height * visible_height / total).max(1);
        let thumb_offset = if max_scroll > 0 {
            position * (track - thumb) / max_scroll
        } else {
            0
        };
        (thumb, thumb_offset)
    }

    pub fn visible_scroll(&self, visible_height: usize) -> VisibleRegion<'_> {
        if self.elements_cache.is_empty() || visible_height == 0 {
            return VisibleRegion { elements: &[], skip_lines: 0 };
        }

        let total = self.total_lines;
        let max_scroll = total.saturating_sub(visible_height);
        let scroll = self.scroll.min(max_scroll);

        let viewport_end = total.saturating_sub(scroll);
        let viewport_start = viewport_end.saturating_sub(visible_height);

        let mut cum = 0usize;
        let mut start_idx = 0;
        let mut skip_lines = 0;

        for (i, count) in self.line_counts.iter().enumerate() {
            let next_cum = cum + count;
            if next_cum > viewport_start {
                start_idx = i;
                skip_lines = viewport_start.saturating_sub(cum);
                break;
            }
            cum = next_cum;
        }

        let mut end_idx = self.elements_cache.len();
        cum = 0;
        for (i, count) in self.line_counts.iter().enumerate() {
            cum += count;
            if cum >= viewport_end {
                end_idx = i + 1;
                break;
            }
        }

        VisibleRegion {
            elements: &self.elements_cache[start_idx..end_idx.min(self.elements_cache.len())],
            skip_lines,
        }
    }

    pub fn total_tokens(&self) -> usize {
        self.messages.iter().map(|m| crate::tokens::estimate_tokens(&m.content)).sum()
    }

    pub fn compact(&mut self, keep_recent_tokens: usize) -> String {
        let total = self.total_tokens();
        if total <= keep_recent_tokens {
            return format!("Session has {} tokens, no compaction needed", total);
        }
        let mut accumulated = 0usize;
        let mut cut_idx = 0usize;
        for (i, msg) in self.messages.iter().enumerate().rev() {
            accumulated += crate::tokens::estimate_tokens(&msg.content);
            if accumulated >= keep_recent_tokens {
                cut_idx = i;
                break;
            }
        }
        while cut_idx < self.messages.len() {
            match self.messages[cut_idx].role {
                Role::User | Role::Assistant => break,
                _ => cut_idx += 1,
            }
        }
        if cut_idx == 0 {
            return "Cannot compact: all messages are recent".to_string();
        }
        let removed_count = cut_idx;
        self.messages.drain(..cut_idx);
        let summary = format!("[Compacted: {} earlier messages removed, keeping ~{} tokens]", removed_count, keep_recent_tokens);
        self.messages.insert(0, ChatMessage {
            role: Role::System,
            content: summary.clone(),
            timestamp: now(),
            id: "compaction".to_string(),
        });
        self.messages_changed();
        summary
    }
}

pub fn now() -> f64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|d| d.as_secs_f64())
        .unwrap_or(0.0)
}

