pub fn check_bash_safety(command: &str) -> Option<&'static str> {
    let cmd = command.trim().to_lowercase();
    if cmd.contains("rm -rf /") || cmd.contains("rm -rf /*") || cmd.contains("rm -rf ~") {
        return Some("rm -rf on system directories or home is blocked");
    }
    if cmd.starts_with("dd ") && cmd.contains("of=/dev/") {
        return Some("dd writing to block devices is blocked");
    }
    if cmd.contains("> /dev/sda") || cmd.contains("> /dev/nvme") || cmd.contains("> /dev/hd") {
        return Some("writing directly to block devices is blocked");
    }
    if cmd.starts_with("mkfs") || cmd.starts_with("mkfs.") {
        return Some("mkfs is blocked");
    }
    if cmd.contains(":|:") && cmd.contains("};") {
        return Some("fork bombs are blocked");
    }
    if cmd.contains("chmod -r 777 /") || cmd.contains("chmod -r 000 /") {
        return Some("recursive chmod on root is blocked");
    }
    if cmd.starts_with("sudo ") && (cmd.contains(" rm ") || cmd.contains(" dd ")) {
        return Some("sudo with destructive commands is blocked");
    }
    None
}

pub const DEFAULT_MAX_LINES: usize = 2000;
pub const DEFAULT_MAX_BYTES: usize = 50 * 1024;

#[derive(Debug, Clone)]
pub struct TruncationPolicy {
    pub max_lines: usize,
    pub max_bytes: usize,
}

impl Default for TruncationPolicy {
    fn default() -> Self {
        Self {
            max_lines: DEFAULT_MAX_LINES,
            max_bytes: DEFAULT_MAX_BYTES,
        }
    }
}

#[derive(Debug, Clone)]
pub struct TruncatedOutput {
    pub content: String,
    pub was_truncated: bool,
    pub total_lines: usize,
    pub total_bytes: usize,
    pub output_lines: usize,
    pub output_bytes: usize,
}

impl TruncatedOutput {
    pub fn full(content: String) -> Self {
        let lines = content.lines().count();
        let bytes = content.len();
        Self {
            content,
            was_truncated: false,
            total_lines: lines,
            total_bytes: bytes,
            output_lines: lines,
            output_bytes: bytes,
        }
    }
}

pub fn truncate_head(content: &str, policy: &TruncationPolicy) -> TruncatedOutput {
    let lines: Vec<&str> = content.lines().collect();
    let total_lines = lines.len();
    let total_bytes = content.len();

    if total_lines <= policy.max_lines && total_bytes <= policy.max_bytes {
        return TruncatedOutput::full(content.to_string());
    }

    let mut output = Vec::new();
    let mut output_bytes = 0;

    for (i, line) in lines.iter().enumerate() {
        if i >= policy.max_lines {
            break;
        }
        let line_bytes = line.len() + 1;
        if output_bytes + line_bytes > policy.max_bytes {
            break;
        }
        output.push(*line);
        output_bytes += line_bytes;
    }

    let out_str = output.join("\n");
    TruncatedOutput {
        content: out_str.clone(),
        was_truncated: true,
        total_lines,
        total_bytes,
        output_lines: output.len(),
        output_bytes: out_str.len(),
    }
}

pub fn truncate_tail(content: &str, policy: &TruncationPolicy) -> TruncatedOutput {
    let lines: Vec<&str> = content.lines().collect();
    let total_lines = lines.len();
    let total_bytes = content.len();

    if total_lines <= policy.max_lines && total_bytes <= policy.max_bytes {
        return TruncatedOutput::full(content.to_string());
    }

    let mut output = Vec::new();
    let mut output_bytes = 0;

    for (_i, line) in lines.iter().enumerate().rev() {
        if output.len() >= policy.max_lines {
            break;
        }
        let line_bytes = line.len() + 1;
        if output_bytes + line_bytes > policy.max_bytes {
            break;
        }
        output.push(*line);
        output_bytes += line_bytes;
    }

    output.reverse();
    let out_str = output.join("\n");
    TruncatedOutput {
        content: out_str.clone(),
        was_truncated: true,
        total_lines,
        total_bytes,
        output_lines: output.len(),
        output_bytes: out_str.len(),
    }
}

//! Global TOML config (~/.runie/config.toml)

use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::path::PathBuf;

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct ModelsSection {
    pub default: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ModelProvider {
    #[serde(rename = "type")]
    pub provider_type: Option<String>,
    pub base_url: String,
    pub api_key: String,
}

#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct Config {
    pub provider: Option<String>,
    pub model: Option<String>,
    #[serde(default)]
    pub models: ModelsSection,
    #[serde(default)]
    pub model_providers: HashMap<String, ModelProvider>,
}

impl Config {
    pub fn load() -> Self {
        let path = Self::path();
        if !path.exists() {
            return Self::default();
        }
        match std::fs::read_to_string(&path) {
            Ok(text) => toml::from_str(&text).unwrap_or_default(),
            Err(_) => Self::default(),
        }
    }

    pub fn save(&self) -> anyhow::Result<()> {
        let path = Self::path();
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        std::fs::write(&path, toml::to_string_pretty(self)?)?;
        Ok(())
    }

    pub fn path() -> PathBuf {
        dirs::home_dir()
            .unwrap_or_else(|| PathBuf::from("."))
            .join(".runie")
            .join("config.toml")
    }

    pub fn default_model(&self) -> Option<&str> {
        self.models.default.as_deref().or(self.model.as_deref())
    }

    pub fn provider_for_model(&self, full_model: &str) -> Option<&ModelProvider> {
        let prefix = full_model.split('/').next().unwrap_or(full_model);
        self.model_providers.get(prefix)
    }
}

